import{_ as i,o as a,c as t,a3 as n}from"./chunks/framework.q4B3G9ZH.js";const r=JSON.parse('{"title":"一些踩坑","description":"","frontmatter":{},"headers":[],"relativePath":"C++/踩坑记录.md","filePath":"C++/踩坑记录.md","lastUpdated":null}'),l={name:"C++/踩坑记录.md"};function e(p,s,h,o,d,k){return a(),t("div",null,[...s[0]||(s[0]=[n(`<h1 id="一些踩坑" tabindex="-1">一些踩坑 <a class="header-anchor" href="#一些踩坑" aria-label="Permalink to &quot;一些踩坑&quot;">​</a></h1><h2 id="link1318" tabindex="-1">LINK1318 <a class="header-anchor" href="#link1318" aria-label="Permalink to &quot;LINK1318&quot;">​</a></h2><p>遇到了一个非常匪夷所思的报错，明明没有任何改动，但是这个报错折腾了我一个下午。报错信息如下：</p><div class="language-C++ vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">C++</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">解决LNK1318: 非意外的 PDB 错误: </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">FORMAT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">11</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>重启，重新生成有没有作用。</p><p>最后成功编译成功的方法是，把项目路径下的所有相关pdb文件全部删除，然后再升成，就可以了。</p><p>感觉还是有一点匪夷所思，因为清理后生成好像没有解决这个问题。</p><p>后面需要再细细探究一下编译和清理到底是在干什么</p><p>参考链接：<a href="https://blog.csdn.net/Chauncey_Yu/article/details/100672384" target="_blank" rel="noreferrer">https://blog.csdn.net/Chauncey_Yu/article/details/100672384</a></p><h2 id="类型歧义" tabindex="-1">类型歧义 <a class="header-anchor" href="#类型歧义" aria-label="Permalink to &quot;类型歧义&quot;">​</a></h2><p>在调用rapidjson的一个方法的时候，直接传递long long类型在NDK25的clang编译器下，会有一个二义性的编译报错</p><blockquote><p>按我的个人理解，long long是一个精确的类型，不应该会出现二义性</p></blockquote><div class="language-C++ vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">C++</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">assetData.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">AddMember</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;downloadTime&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">static_cast&lt;int64_t&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(config-&gt;downloadTime), allocator);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">assetData.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">AddMember</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;lastUseTime&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">static_cast&lt;int64_t&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(config-&gt;lastUseTime), allocator);</span></span></code></pre></div><p>下面是ai给出的解答，暂且当做目前的答案，long long在进行模板匹配的时候，会有下面的情况，会导致歧义</p><div class="language-C++ vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">C++</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 候选1：long long → int64_t（通常相同类型，完美匹配）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">GenericValue</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int64_t</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(downloadTime));</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 候选2：long long → uint64_t（有符号到无符号，可能但危险）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">GenericValue</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">uint64_t</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(downloadTime));</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 候选3：long long → double（整数到浮点数，精度可能丢失）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">GenericValue</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">double</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(downloadTime));</span></span></code></pre></div><p>在不同的平台上 long和long long不总是相同的</p><p>在进行重载决议的时候有了不同的状态</p><blockquote><p><code>static_cast&lt;int64_t&gt;</code>有效而 <code>static_cast&lt;long long&gt;</code>可能无效的原因是：</p><ol><li>转换序列优先级：用户定义的转换序列（如 static_cast）在重载决议中有特殊优先级</li><li>精确匹配：<code>static_cast&lt;int64_t&gt;</code>创建了到 RapidJSON 构造函数的精确匹配</li><li>类型标识：即使底层类型相同，编译器在重载决议时可能区分类型别名和基础类型</li><li>接口设计：RapidJSON 是针对标准库类型（如 <code>int64_t</code>）设计的，而不是特定平台的基础类型</li></ol><p>根本原因：C++ 重载决议规则非常复杂，<code>static_cast&lt;int64_t&gt;</code>创建了一个明确的转换路径，告诉编译器&quot;我明确想要使用 <code>int64_t</code>版本&quot;，而直接使用 <code>long long</code>或 <code>static_cast&lt;long long&gt;</code>让编译器自己猜测意图</p></blockquote><p>暂时的一个结论就是，int64_t这样的写法表达常常是更精确的，不要依赖long 和long long这种写法</p>`,19)])])}const g=i(l,[["render",e]]);export{r as __pageData,g as default};
